    private array $data=[];
    public function __construct(private readonly string $file,private readonly string $documentDir)
    {
        if(!is_dir(dirname($file)))@mkdir(dirname($file),0775,true);
        if(!is_dir($documentDir))@mkdir($documentDir,0775,true);
        $loaded=is_file($file)?json_decode((string)file_get_contents($file),true):null;
        $this->data=is_array($loaded)?$loaded:$this->seed();
        $this->save();
    }
