    private function save():void{file_put_contents($this->file,(string)json_encode($this->data,JSON_PRETTY_PRINT|JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES),LOCK_EX);}
    private function id(string $prefix):string{return $prefix.'-'.bin2hex(random_bytes(8));}
    private function find(string $bucket,string $id):array{foreach($this->data[$bucket] as $row)if(($row['id']??'')===$id)return $row;throw new ApiException('Data tidak ditemukan.',404);}
    private function replace(string $bucket,array $row):void{foreach($this->data[$bucket] as $n=>$existing)if(($existing['id']??'')===($row['id']??'')){$this->data[$bucket][$n]=$row;$this->save();return;}$this->data[$bucket][]=$row;$this->save();}
    private function filterItems(array $f):array
    {
        $rows=$this->data['items'];$allowed=$f['allowed_types']??[];$q=mb_strtolower(trim((string)($f['query']??'')));
        $rows=array_values(array_filter($rows,function($i)use($f,$allowed,$q){
            if(!empty($f['only_inactive'])&&($i['is_active']??true))return false;if(empty($f['include_inactive'])&&empty($f['only_inactive'])&&!($i['is_active']??false))return false;
            if($allowed&&!in_array($i['item_type'],$allowed,true))return false;if(!empty($f['type'])&&$i['item_type']!==strtoupper((string)$f['type']))return false;
            if(!empty($f['facility_id'])&&($i['facility_id']??'')!==$f['facility_id'])return false;if(($f['location_scope']??'')==='tpp'&&empty($i['at_tpp']))return false;if(($f['location_scope']??'')==='tps'&&!empty($i['at_tpp']))return false;
            if(!empty($f['status'])&&($i['status_code']??'')!==$f['status'])return false;if(!empty($f['item_kind'])&&($i['item_kind']??'')!==$f['item_kind'])return false;if(!empty($f['goods_condition'])&&($i['goods_condition']??'')!==$f['goods_condition'])return false;
            if($q!==''&&!str_contains(mb_strtolower((string)($i['search_text']??implode(' ',array_filter($i,'is_scalar')))),$q))return false;return true;
        }));
        usort($rows,fn($a,$b)=>strcmp((string)($b['updated_at']??''),(string)($a['updated_at']??'')));
        $offset=max(0,(int)($f['offset']??0));$limit=(int)($f['limit']??0);return $limit>0?array_slice($rows,$offset,$limit):array_slice($rows,$offset);
    }
    public function facilities(bool $includeInactive=false):array{return array_values(array_filter($this->data['facilities'],fn($f)=>$includeInactive||!empty($f['active'])));}
    public function updateFacilityCapacity(string $id,float $yard,float $shed):array{$f=$this->find('facilities',$id);$f['yard_capacity']=max(0,$yard);$f['shed_capacity']=max(0,$shed);$this->replace('facilities',$f);return $f;}
    public function dashboard():array
    {
        $items=$this->filterItems(['include_inactive'=>false]);$types=['BTD'=>0,'BDN'=>0,'BMMN'=>0,'TITIPAN'=>0];foreach($items as $i)$types[$i['item_type']]++;
        $summary=fn(array $rows)=>['documents'=>count(array_unique(array_column($rows,'determination_no'))),'fcl'=>count(array_unique(array_filter(array_map(fn($i)=>$i['load_type']==='FCL'?$i['physical_unit_id']:null,$rows)))),'lcl'=>count(array_filter($rows,fn($i)=>$i['load_type']==='LCL'))];
        $facility=[];foreach($this->facilities() as $f){$row=['facility_id'=>$f['id'],'facility_name'=>$f['name'],'btd'=>0,'bdn'=>0,'bmmn'=>0,'titipan'=>0,'yard_used'=>$f['yard_used'],'yard_capacity'=>$f['yard_capacity'],'shed_used'=>$f['shed_used'],'shed_capacity'=>$f['shed_capacity']];foreach($items as $i)if(($i['facility_id']??'')===$f['id'])$row[strtolower($i['item_type'])]++;$row['total']=$row['btd']+$row['bdn']+$row['bmmn']+$row['titipan'];$facility[]=$row;}
        return ['active_total'=>count($items),'btd_total'=>$types['BTD'],'bdn_total'=>$types['BDN'],'bmmn_total'=>$types['BMMN'],'titipan_total'=>$types['TITIPAN'],'active_summary'=>$summary($items),'btd_summary'=>$summary(array_values(array_filter($items,fn($i)=>$i['item_type']==='BTD'))),'bdn_summary'=>$summary(array_values(array_filter($items,fn($i)=>$i['item_type']==='BDN'))),'bmmn_summary'=>$summary(array_values(array_filter($items,fn($i)=>$i['item_type']==='BMMN'))),'titipan_summary'=>$summary(array_values(array_filter($items,fn($i)=>$i['item_type']==='TITIPAN'))),'auction_active'=>count(array_filter($this->data['dispositions'],fn($p)=>$p['disposition_type']==='lelang'&&$p['is_active'])),'destruction_active'=>count(array_filter($this->data['dispositions'],fn($p)=>$p['disposition_type']==='musnah'&&$p['is_active'])),'grant_active'=>count(array_filter($this->data['dispositions'],fn($p)=>$p['disposition_type']==='hibah'&&$p['is_active'])),'facility_breakdown'=>$facility,'recent_events'=>array_slice(array_reverse($this->data['events']),0,8),'attention_items'=>array_slice(array_values(array_filter($items,fn($i)=>strtotime((string)$i['determination_date'])<strtotime('-45 days'))),0,8)];
    }
    public function listInventory(array $f=[]):array{return $this->filterItems($f);}
    public function countInventory(array $f=[]):int{unset($f['limit'],$f['offset']);return count($this->filterItems($f));}
    public function inventorySummary(array $f=[]):array{return ['total'=>$this->countInventory($f)];}
    public function getInventory(string $id):array{return $this->find('items',$id);}
    public function createInventories(array $inputs):array{$out=[];foreach($inputs as $in)$out[]=$this->createInventory($in);return$out;}
    public function createInventory(array $in):array
    {
        $type=strtoupper(trim((string)($in['type']??$in['item_type']??'')));if(!in_array($type,Domain::TYPES,true))throw new ApiException('Jenis inventory tidak valid.',422);$description=trim((string)($in['description']??''));$number=trim((string)($in['determination_no']??''));if($number===''||$description==='')throw new ApiException('Nomor dokumen dan uraian barang wajib diisi.',422);
        $id=$this->id('inv');$fid=trim((string)($in['facility_id']??''));$fname='';foreach($this->facilities() as $f)if($f['id']===$fid)$fname=$f['name'];$load=strtoupper(trim((string)($in['load_type']??'')))?:(!empty($in['container_no'])?'FCL':'LCL');$container=strtoupper((string)preg_replace('/[^A-Z0-9]/i','',(string)($in['container_no']??'')));$date=trim((string)($in['determination_date']??''))?:date('Y-m-d');
        $row=$this->item($id,$type,trim((string)($in['reference_no']??''))?:$number,$container,strtoupper((string)($in['container_size']??'')),$load,$description,(float)($in['quantity']??1),(string)($in['unit']??'KOLI'),(int)($in['goods_value']??0),$fid,$fname,$date.'T00:00:00Z',$type==='TITIPAN'?'barang_titipan_aktif':($fid!==''?'ditetapkan':'masih_di_tps'),$type==='TITIPAN'?'Barang titipan aktif':($fid!==''?'Ditetapkan sebagai '.$type:'Masih di TPS'));
        foreach($in as $k=>$v)if(array_key_exists($k,$row)&&$v!==''&&$v!==null&&!in_array($k,['container_no','load_type','container_size'],true))$row[$k]=$v;$row['container_no']=$container;$row['load_type']=$load;$row['container_size']=strtoupper((string)($in['container_size']??$row['container_size']));$row['created_by']=$in['actor']??'Administrator';$this->data['items'][]=$row;$this->data['events'][]=['id'=>$this->id('evt'),'inventory_id'=>$id,'code'=>$row['status_code'],'label'=>$row['status_label'],'document_no'=>$number,'document_date'=>$date,'notes'=>'Pencatatan awal','actor'=>$row['created_by'],'created_at'=>gmdate('c'),'document_id'=>$in['document_id']??null];$this->save();return$row;
    }
    public function deleteInventory(string $id,string $actor):void{$this->data['items']=array_values(array_filter($this->data['items'],fn($i)=>$i['id']!==$id));$this->data['events']=array_values(array_filter($this->data['events'],fn($e)=>($e['inventory_id']??'')!==$id));$this->save();}
    public function addInventoryEvent(string $id,array $in):array{$item=$this->getInventory($id);$code=(string)($in['code']??'');$label=$code===''?'Pembaruan':ucwords(str_replace('_',' ',$code));$item['status_code']=$code?:$item['status_code'];$item['status_label']=$label;$item['updated_at']=gmdate('c');if($code==='pemindahan'){foreach($this->facilities() as $f)if($f['id']===($in['target_facility_id']??'')){$item['facility_id']=$f['id'];$item['facility_name']=$f['name'];$item['at_tpp']=true;$item['location']=$f['name'];}}if($code==='pengeluaran_barang')$item['is_active']=false;if($code==='penetapan_bmmn')$item['item_type']='BMMN';foreach(['description','item_kind','quantity','unit','goods_condition','goods_value','hs_code','restriction_rule','allocation_purpose','exit_type'] as $k)if(array_key_exists($k,$in)&&$in[$k]!=='')$item[$k]=$in[$k];$this->replace('items',$item);$event=['id'=>$this->id('evt'),'inventory_id'=>$id,'code'=>$code,'label'=>$label,'document_no'=>$in['document_no']??'','document_date'=>$in['document_date']??date('Y-m-d'),'notes'=>$in['notes']??'','actor'=>$in['actor']??'Administrator','created_at'=>gmdate('c'),'document_id'=>$in['document_id']??null];$this->data['events'][]=$event;$this->save();return['item'=>$item,'event'=>$event];}
    public function applyCensus(string $id,array $lines,array $in):array{$out=[];foreach($lines as $line){$line['code']='pencacahan';$line+=$in;$out[]=$this->addInventoryEvent((string)($line['inventory_id']??$id),$line)['item'];}return$out;}
    public function relocateLoad(string $id,array $allocations,array $in):array{$out=[];foreach($allocations as $a){$target=(string)($a['inventory_id']??$id);$item=$this->getInventory($target);foreach(['load_type','container_no','container_size','estimated_volume_m3','physical_unit_id','occupancy_primary'] as $k)if(array_key_exists($k,$a))$item[$k]=$a[$k];$item['updated_at']=gmdate('c');$this->replace('items',$item);$out[]=$item;}$in['code']='pindah_bongkar_kontainer';$this->addInventoryEvent($id,$in);return$out;}
    public function timeline(string $id):array{return array_values(array_filter($this->data['events'],fn($e)=>($e['inventory_id']??'')===$id));}
    public function processTimeline(string $id):array{return array_values(array_filter($this->data['events'],fn($e)=>($e['disposition_id']??'')===$id));}
    public function listEvents(int $limit=50000):array{return array_slice($this->data['events'],-$limit);}
    public function listDispositions(array $f=[]):array{$rows=$this->data['dispositions'];$rows=array_values(array_filter($rows,function($p)use($f){if(!empty($f['type'])&&$p['disposition_type']!==$f['type'])return false;if(empty($f['include_inactive_inventory'])&&isset($p['inventory_is_active'])&&!$p['inventory_is_active'])return false;if(!empty($f['status'])&&$p['status_code']!==$f['status'])return false;return true;}));$offset=(int)($f['offset']??0);$limit=(int)($f['limit']??0);return$limit?array_slice($rows,$offset,$limit):array_slice($rows,$offset);}
    public function countDispositions(array $f=[]):int{unset($f['limit'],$f['offset']);return count($this->listDispositions($f));}
