    public function createRole(array $in):array{$r=['id'=>$this->id('role'),'name'=>trim((string)$in['name']),'description'=>trim((string)($in['description']??'')),'permissions'=>Domain::normalizePermissions((array)($in['permissions']??[])),'active'=>true,'assigned_users'=>0,'created_at'=>gmdate('c')];$this->data['roles'][]=$r;$this->save();return$r;}
