    public function setRoleActive(string $id,bool $active):void{$r=$this->find('roles',$id);$r['active']=$active;$this->replace('roles',$r);}
    public function deleteRole(string $id):array{$r=$this->find('roles',$id);if(count(array_filter($this->data['users'],fn($u)=>($u['role_id']??'')===$id))>0)throw new ApiException('Role masih digunakan oleh pengguna.',409);$this->data['roles']=array_values(array_filter($this->data['roles'],fn($x)=>$x['id']!==$id));$this->save();return$r;}
    public function parameterOptions(string $group='',bool $includeInactive=true):array{$p=array_values(array_filter($this->data['parameters'],fn($x)=>($group===''||$x['group_code']===$group)&&($includeInactive||!empty($x['active']))));if($group===''||$group==='tpp')foreach($this->facilities($includeInactive) as $f)$p[]=['id'=>'facility--'.$f['id'],'group_code'=>'tpp','code'=>$f['id'],'label'=>$f['name'],'active'=>$f['active'],'system'=>true,'sort_order'=>$f['sort_order'],'created_at'=>$f['created_at']];return$p;}
    public function createParameter(array $in):array{$group=(string)$in['group_code'];if($group==='tpp'){$f=['id'=>strtolower(preg_replace('/[^a-z0-9]+/i','-',(string)($in['code']??$in['label']))),'name'=>(string)$in['label'],'active'=>true,'sort_order'=>(int)($in['sort_order']??999),'yard_capacity'=>0,'yard_used'=>0,'shed_capacity'=>0,'shed_used'=>0,'created_at'=>gmdate('c')];$this->data['facilities'][]=$f;$this->save();return$f;}$p=['id'=>$this->id('param'),'group_code'=>$group,'code'=>strtolower(preg_replace('/[^a-z0-9]+/i','_',(string)($in['code']??$in['label']))),'label'=>(string)$in['label'],'applies_to'=>implode(',',(array)($in['applies_to']??[])),'sort_order'=>(int)($in['sort_order']??999),'active'=>true,'system'=>false,'created_at'=>gmdate('c')];$this->data['parameters'][]=$p;$this->save();return$p;}
    public function updateParameter(string $id,array $in):array{if(str_starts_with($id,'facility--')){$f=$this->find('facilities',substr($id,10));$f['name']=(string)$in['label'];$f['sort_order']=(int)($in['sort_order']??$f['sort_order']);$this->replace('facilities',$f);return$f;}$p=$this->find('parameters',$id);$p['label']=(string)$in['label'];$p['sort_order']=(int)($in['sort_order']??$p['sort_order']);$p['applies_to']=implode(',',(array)($in['applies_to']??[]));$this->replace('parameters',$p);return$p;}
    public function setParameterActive(string $id,bool $active):void{if(str_starts_with($id,'facility--')){$f=$this->find('facilities',substr($id,10));$f['active']=$active;$this->replace('facilities',$f);}else{$p=$this->find('parameters',$id);$p['active']=$active;$this->replace('parameters',$p);}}
    public function createDocument(array $file,string $actor):array{$content=(string)file_get_contents((string)$file['tmp_name']);$id=$this->id('doc');$name=basename((string)$file['name']);$path=$id.'-'.preg_replace('/[^A-Za-z0-9._-]/','_',$name);file_put_contents($this->documentDir.'/'.$path,$content);$d=['id'=>$id,'file_name'=>$name,'mime_type'=>$file['type']??'application/octet-stream','size_bytes'=>strlen($content),'uploaded_by'=>$actor,'storage_bucket'=>'demo','storage_path'=>$path,'sha256'=>hash('sha256',$content),'created_at'=>gmdate('c')];$this->data['documents'][]=$d;$this->save();return$d;}
    public function getDocument(string $id):array{$d=$this->find('documents',$id);$content=(string)file_get_contents($this->documentDir.'/'.$d['storage_path']);return[$d,$content];}
    public function documentAccess(string $id):array{$out=[];foreach($this->data['events'] as $event){if(($event['document_id']??'')!==$id)continue;try{$item=$this->getInventory((string)($event['inventory_id']??''));$out[]=['inventory'=>$item,'disposition_type'=>$event['disposition_type']??'','event_code'=>$event['code']??''];}catch(\Throwable){}}if(!$out)throw new ApiException('Dokumen tidak ditemukan.',404);return$out;}
    public function notifications(array $allowed):array{return['count'=>0,'items'=>[]];}
    public function audit(array $e):void{}
    public function listReconciliations(int $limit=5000):array{return array_slice(array_reverse($this->data['reconciliations']),0,$limit);}
    public function reconcile(array $in):array{if(($in['type']??'')==='found_not_recorded'){$item=$this->createInventory(($in['new_item']??[])+['actor'=>$in['actor']??'Administrator']);$r=['id'=>$this->id('rec'),'reconciliation_type'=>'found_not_recorded','action'=>'added','inventory_id'=>$item['id'],'inventory_reference'=>$item['reference_no'],'inventory_type'=>$item['item_type'],'result_status_code'=>$item['status_code'],'result_status_label'=>$item['status_label'],'notes'=>$in['notes']??'','actor'=>$in['actor']??'Administrator','created_at'=>gmdate('c')];}else{$item=$this->getInventory((string)$in['inventory_id']);$item['is_active']=false;$item['status_code']='rekonsiliasi_tidak_ditemukan';$item['status_label']='Tidak ditemukan di lapangan';$this->replace('items',$item);$r=['id'=>$this->id('rec'),'reconciliation_type'=>'recorded_not_found','action'=>'removed','inventory_id'=>$item['id'],'inventory_reference'=>$item['reference_no'],'inventory_type'=>$item['item_type'],'result_status_code'=>$item['status_code'],'result_status_label'=>$item['status_label'],'notes'=>$in['notes']??'','actor'=>$in['actor']??'Administrator','created_at'=>gmdate('c')];}$this->data['reconciliations'][]=$r;$this->save();return[$r,$item];}
    public function correctInventory(array $payload):array
    {
        $item=$this->getInventory((string)($payload['p_inventory_id']??''));
        $changes=(array)($payload['p_changes']??[]);$details=[];
        foreach($changes as $key=>$value){
            $before=$item[$key]??null;
            if($before==$value)continue;
            $details[]=['section'=>'inventory','entity_id'=>$item['id'],'context'=>'Data utama barang','field'=>$key,'before'=>(string)($before??''),'after'=>(string)($value??'')];
            $item[$key]=$value;
        }
        if(!$details)throw new ApiException('Tidak ada perubahan data yang terdeteksi.',422);
        $item['updated_at']=gmdate('c');$this->replace('items',$item);
        $record=['id'=>$this->id('rec'),'reconciliation_type'=>'data_correction','action'=>'corrected','inventory_id'=>$item['id'],'inventory_reference'=>$item['reference_no'],'inventory_type'=>$item['item_type'],'previous_status_code'=>$item['status_code'],'previous_status_label'=>$item['status_label'],'result_status_code'=>$item['status_code'],'result_status_label'=>$item['status_label'],'correction_reason'=>$payload['p_reason']??'','change_details'=>$details,'notes'=>'Perubahan data barang','actor'=>$payload['p_actor']??'Administrator','created_at'=>gmdate('c')];
        $this->data['reconciliations'][]=$record;$this->save();return['inventory'=>$item,'reconciliation'=>$record];
    }
    public function listCorrections(int $limit=5000):array{return array_slice(array_values(array_filter(array_reverse($this->data['reconciliations']),fn($r)=>($r['reconciliation_type']??'')==='data_correction')),0,$limit);}
}
